HOTEL_INFO["https://static.peakview.bg/img/data2/94/hoteli/1900/BIG_IMG_17007433411900.jpg"]={images:["https://static.peakview.bg/img/data2/94/hoteli/1900/BIG_IMG_17007433411900.jpg","https://static.peakview.bg/img/data2/94/hoteli/1900/BIG_IMG2_17007433411900.jpg","https://static.peakview.bg/img/data2/94/hoteli/1900/BIG_IMG3_17007433421900.jpg","https://static.peakview.bg/img/data2/94/hoteli/1900/BIG_IMG4_17007433421900.jpg","https://static.peakview.bg/img/data2/94/hoteli/1900/BIG_IMG5_17007433431900.jpg","https://static.peakview.bg/img/data2/94/hoteli/1900/BIG_IMG6_17007433431900.jpg","https://static.peakview.bg/img/data2/94/hoteli/1900/BIG_IMG7_17007433431900.jpg","https://static.peakview.bg/img/data2/94/hoteli/1900/BIG_IMG8_17007433441900.jpg","https://static.peakview.bg/img/data2/94/hoteli/1900/BIG_IMG9_17007433451900.jpg","https://static.peakview.bg/img/data2/94/hoteli/1900/BIG_IMG10_17007433451900.jpg","https://static.peakview.bg/img/data2/94/hoteli/1900/BIG_IMG11_17007433451900.jpg"],stars:5,location:"Анталия, Лара , Турция",desc:"<p><strong>BAYOU VILLAS</strong></p><p>Bayou Villas-Ultra се намира в Анталия, на 2 километра от Lara Halk Plaji. Ол инклузив предлага помещения за настаняване с открит плувен басейн, безплатен частен паркинг, фитнес център и градина. На разположение на гостите има детски клуб, ресторант, воден парк и тераса. Предлага денонощна рецепция, летищни трансфери, рум-сървиз и безплатен WiFi на цялата територия.</p><p>Стаите в хотела разполагат с климатик, кът за сядане, телевизор с плосък екран със сателитни канали, кухня, кът за хранене, сейф и собствена баня с душ, безплатни тоалетни принадлежности и сешоар. В Bayou Villas-Ultra Ол инклузив всяка стая разполага със спално бельо и кърпи.</p><p>Сутрин се сервира континентална или халал закуска.</p><p>Вили Bayou - Ultra Ол инклузив предлага 5-звездно настаняване със сауна, хидромасажна вана и СПА център.</p><p>Портата на Адриан и часовниковата кула на Анталия са на 16 километра. Най-близкото летище е Анталия, на 5 км от Bayou Villas-Ultra. Ол инклузив. </p>",rooms:[{n:"Възрастен в двойна стая - BAYOU VILLA 1 BEDROOM - UAI",p:[4891,4851,4758,3963,3963,3951,3896,0,0]},{n:"2 възр. - BAYOU VILLA 1 BEDROOM - UAI",p:[9781,9701,9516,7925,7925,7902,7792,0,0]},{n:"Възрастен в двойна стая - BAYOU VILLA 2 BEDROOMS - UAI",p:[8757,7654,7645,7355,7355,7344,7334,8746,7694]},{n:"2 възр. - BAYOU VILLA 2 BEDROOMS - UAI",p:[17513,15307,15290,14710,14710,14687,14668,17491,15387]},{n:"Възрастен в двойна стая - BAYOU VILLA 3 BEDROOMS - UAI",p:[13598,9721,9733,9565,9565,9554,9508,13586,9760]},{n:"2 възр. - BAYOU VILLA 3 BEDROOMS - UAI",p:[27195,19441,19465,19129,19129,19107,19015,27172,19520]},{n:"Възрастен в двойна стая - BAYOU VILLA 4 BEDROOMS - UAI",p:[17649,12608,12641,12604,12604,12593,12575,17638,12647]},{n:"2 възр. - BAYOU VILLA 4 BEDROOMS - UAI",p:[35298,25215,25282,25207,25207,25185,25150,35276,25294]}],dates:["18.06.2026","10.09.2026","17.09.2026","24.09.2026","01.10.2026","08.10.2026","15.10.2026","11.06.2026","03.09.2026"]};
